import React, { useState } from 'react';
import TaskList from './components/TaskList';
import Counter from './components/Counter';
import UserCard from './components/UserCard';

function App() {
  const [tasks, setTasks] = useState([
    { id: 1, text: 'Buy groceries', done: false },
    { id: 2, text: 'Read a book', done: false },
    { id: 3, text: 'Go for a walk', done: false },
  ]);

  const [newTask, setNewTask] = useState('');

  // BUG 1: uses tasks.length as id — duplicate ids if tasks are deleted then added
  const addTask = () => {
    if (newTask === '') return;
    setTasks([...tasks, { id: tasks.length, text: newTask, done: false }]);
    setNewTask('');
  };

  const toggleTask = (id) => {
    setTasks(tasks.map(task =>
      task.id === id ? { ...task, done: !task.done } : task
    ));
  };

  const user = { name: 'Alex', age: 28 };

  return (
    <div style={{ maxWidth: 600, margin: '40px auto', fontFamily: 'sans-serif' }}>
      <h1>My Debug App</h1>

      {/* BUG 2: email prop not passed to UserCard */}
      <UserCard name={user.name} age={user.age} />

      <hr />

      <Counter />

      <hr />

      <h2>Tasks</h2>
      <div style={{ display: 'flex', gap: 8, marginBottom: 16 }}>
        <input
          value={newTask}
          onChange={e => setNewTask(e.target.value)}
          placeholder="New task..."
          style={{ flex: 1, padding: 8 }}
        />
        <button onClick={addTask}>Add</button>
      </div>

      <TaskList tasks={tasks} onToggle={toggleTask} />
    </div>
  );
}

export default App;
